// OpenClaw Follow-up Action Digest
// Fetches /internal/followup-automation, filters recently_contacted,
// formats Telegram digest with suggested messages.
// Stateless — no watermark. Runs once per afternoon.
//
// Runtime: uses Node.js http module (n8n sandbox compatible).

// === CONFIGURATION — edit these after importing ===
const API_BASE = 'CONFIGURE_ME'; // e.g. 'http://localhost:8000'
const API_KEY = 'CONFIGURE_ME';  // OPENCLAW_API_KEY value, or '' for dev
const MAX_DETAILED = 5;          // Show full detail for top N leads

// --- Weekend guard ---
// The schedule trigger fires daily (triggerAtHour format does not support
// weekday restriction). This guard skips weekends. new Date() uses the
// n8n process timezone (set to Europe/Madrid at workflow level).
const now = new Date();
const day = now.getDay();
if (day === 0 || day === 6) return [];

// --- Helpers ---
const http = require('http');

function apiFetch(path) {
  return new Promise((resolve, reject) => {
    const headers = { 'Content-Type': 'application/json' };
    if (API_KEY && API_KEY !== 'CONFIGURE_ME') {
      headers['X-API-Key'] = API_KEY;
    }
    http.get(`${API_BASE}${path}`, { headers }, (res) => {
      let body = '';
      res.on('data', chunk => body += chunk);
      res.on('end', () => {
        if (res.statusCode >= 400) {
          reject(new Error(`API ${path} returned ${res.statusCode}`));
          return;
        }
        try { resolve(JSON.parse(body)); }
        catch (e) { reject(new Error(`Invalid JSON from ${path}`)); }
      });
    }).on('error', reject);
  });
}

function timeSince(dateStr) {
  if (!dateStr) return null;
  const ms = Date.now() - new Date(dateStr.replace(' ', 'T') + 'Z').getTime();
  const hours = Math.floor(ms / 3600000);
  if (hours < 1) return 'hace <1h';
  if (hours < 24) return `hace ${hours}h`;
  const days = Math.floor(hours / 24);
  return `hace ${days}d`;
}

// --- Fetch and filter ---
const data = await apiFetch('/internal/followup-automation');
const actionable = data.items.filter(i => !i.payload.recently_contacted);

if (actionable.length === 0) return [];

// --- Group by rating ---
const groups = { high: [], medium: [], low: [] };
for (const item of actionable) {
  const tier = groups[item.payload.rating];
  if (tier) {
    tier.push(item);
  } else {
    groups.low.push(item);
  }
}

// --- Format message ---
const dayNames = ['Dom', 'Lun', 'Mar', 'Mi\u00e9', 'Jue', 'Vie', 'S\u00e1b'];
const monthNames = ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun', 'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'];
const dateStr = `${dayNames[now.getDay()]} ${now.getDate()} ${monthNames[now.getMonth()]}`;

const lines = [];
lines.push(`\u{1F4CB} Follow-up pendientes \u2014 ${dateStr}`);
lines.push('');
lines.push(`${actionable.length} lead${actionable.length > 1 ? 's' : ''} pendiente${actionable.length > 1 ? 's' : ''} de follow-up`);
lines.push('');

const tierConfig = [
  { key: 'high', emoji: '\u{1F534}', label: 'ALTA' },
  { key: 'medium', emoji: '\u{1F7E1}', label: 'MEDIA' },
  { key: 'low', emoji: '\u{1F7E2}', label: 'BAJA' },
];

let shown = 0;

for (const tier of tierConfig) {
  const items = groups[tier.key];
  if (items.length === 0) continue;

  lines.push(`${tier.emoji} ${tier.label} (${items.length})`);

  for (const item of items) {
    if (shown >= MAX_DETAILED) {
      const remaining = actionable.length - shown;
      lines.push(`  + ${remaining} m\u00e1s`);
      shown = actionable.length;
      break;
    }

    const p = item.payload;
    let contactInfo;
    if (p.contact_attempts_count === 0) {
      contactInfo = 'sin contactar';
    } else {
      const ago = timeSince(p.last_contacted_at);
      contactInfo = `${p.contact_attempts_count} intento${p.contact_attempts_count > 1 ? 's' : ''}${ago ? ', ' + ago : ''}`;
    }

    lines.push(`  \u2022 #${item.lead_id} ${p.name} \u2014 score ${p.score} \u2014 ${contactInfo}`);

    if (p.suggested_message) {
      let msg = p.suggested_message;
      if (msg.length > 120) msg = msg.substring(0, 117) + '...';
      lines.push(`    \u2192 "${msg}"`);
    }

    shown++;
  }

  if (shown >= actionable.length) break;
  lines.push('');
}

lines.push('');
lines.push(`Generado: ${data.generated_at}`);

return [{ json: { text: lines.join('\n') } }];
